#include<bits/stdc++.h>
using namespace std;
int m,n,a[35][35],f[35][35],p[35][35][35];
int main(void){
	cin>>n>>m;
	for(int i=1;i<=n;i++)for(int j=1;j<=m;j++)cin>>a[i][j];
	for(int i=1;i<=n;i++){
		for(int j=0;j<=m;j++){
			for(int k=0;k<=j;k++){
				if(f[i][j]<=f[i-1][j-k]+a[i][k]){
					f[i][j]=f[i-1][j-k]+a[i][k];
					for(int l=1;l<i;l++)p[i][j][l]=p[i-1][j-k][l];
					p[i][j][i]=k;
				}
			}
		}
	}
	cout<<f[n][m]<<'\n';
	for(int i=1;i<=n;i++)cout<<i<<' '<<p[n][m][i]<<'\n';
	return false;
}
